// AI AGENTS: DO NOT EDIT THIS FILE
// Validates: Requirements 1.6, 14.3
import 'package:test/test.dart';
import 'package:cs2dart/src/roslyn_frontend/serialization/frontend_result_deserializer.dart';
import 'package:cs2dart/src/roslyn_frontend/models/frontend_result.dart';
import 'package:cs2dart/src/roslyn_frontend/models/frontend_unit.dart';
import 'package:cs2dart/src/roslyn_frontend/models/generic_syntax_node.dart';
import 'package:cs2dart/src/roslyn_frontend/models/ir_type.dart';
import 'package:cs2dart/src/roslyn_frontend/models/annotations.dart';
import 'package:cs2dart/src/roslyn_frontend/models/resolved_symbol.dart';
import 'package:cs2dart/src/project_loader/models/output_kind.dart';
import 'package:cs2dart/src/project_loader/models/diagnostic.dart';

const _deserializer = FrontendResultDeserializer();

// ---------------------------------------------------------------------------
// JSON builder helpers (test-only serializer)
// ---------------------------------------------------------------------------

Map<String, dynamic> _sourceLocationJson({
  String filePath = '/src/Foo.cs',
  int line = 10,
  int column = 5,
}) =>
    {'filePath': filePath, 'line': line, 'column': column};

Map<String, dynamic> _resolvedSymbolJson({
  String fullyQualifiedName = 'System.String',
  String assemblyName = 'System.Runtime',
  String kind = 'type',
  String? sourcePackageId,
  Map<String, dynamic>? sourceLocation,
  Object? constantValue,
}) {
  final m = <String, dynamic>{
    'fullyQualifiedName': fullyQualifiedName,
    'assemblyName': assemblyName,
    'kind': kind,
  };
  if (sourcePackageId != null) m['sourcePackageId'] = sourcePackageId;
  if (sourceLocation != null) m['sourceLocation'] = sourceLocation;
  if (constantValue != null) m['constantValue'] = constantValue;
  return m;
}

Map<String, dynamic> _namedTypeJson({
  Map<String, dynamic>? symbol,
  List<Map<String, dynamic>> typeArguments = const [],
}) =>
    {
      r'$type': 'NamedType',
      'symbol': symbol ?? _resolvedSymbolJson(),
      'typeArguments': typeArguments,
    };

Map<String, dynamic> _nullableTypeJson(Map<String, dynamic> inner) =>
    {r'$type': 'NullableType', 'inner': inner};

Map<String, dynamic> _functionTypeJson({
  List<Map<String, dynamic>> parameterTypes = const [],
  Map<String, dynamic>? returnType,
}) =>
    {
      r'$type': 'FunctionType',
      'parameterTypes': parameterTypes,
      'returnType': returnType ?? _namedTypeJson(),
    };

Map<String, dynamic> _dynamicTypeJson() => {r'$type': 'DynamicType'};

Map<String, dynamic> _unresolvedTypeJson() => {r'$type': 'UnresolvedType'};

Map<String, dynamic> _syntaxNodeJson({
  int nodeId = 1,
  String kind = 'CompilationUnit',
  List<Map<String, dynamic>> children = const [],
  List<Map<String, dynamic>> annotations = const [],
}) =>
    {
      'nodeId': nodeId,
      'kind': kind,
      'children': children,
      'annotations': annotations,
    };

Map<String, dynamic> _symbolTableJson(Map<String, dynamic> entries) =>
    {'entries': entries};

Map<String, dynamic> _normalizedTreeJson({
  String filePath = '/src/Foo.cs',
  Map<String, dynamic>? root,
  Map<String, dynamic>? symbolTable,
}) =>
    {
      'filePath': filePath,
      'root': root ?? _syntaxNodeJson(),
      'symbolTable': symbolTable ?? _symbolTableJson({}),
    };

Map<String, dynamic> _packageRefJson({
  String packageName = 'Newtonsoft.Json',
  String version = '13.0.1',
  int tier = 1,
  Map<String, dynamic>? dartMapping,
}) {
  final m = <String, dynamic>{
    'packageName': packageName,
    'version': version,
    'tier': tier,
  };
  if (dartMapping != null) m['dartMapping'] = dartMapping;
  return m;
}

Map<String, dynamic> _dartMappingJson({
  String dartPackageName = 'json_serializable',
  String dartImportPath = 'package:json_serializable/json_serializable.dart',
}) =>
    {
      'dartPackageName': dartPackageName,
      'dartImportPath': dartImportPath,
    };

Map<String, dynamic> _frontendUnitJson({
  String projectName = 'MyApp',
  String outputKind = 'exe',
  String targetFramework = 'net8.0',
  String langVersion = '12.0',
  bool nullableEnabled = true,
  List<Map<String, dynamic>> packageReferences = const [],
  List<Map<String, dynamic>> normalizedTrees = const [],
}) =>
    {
      'projectName': projectName,
      'outputKind': outputKind,
      'targetFramework': targetFramework,
      'langVersion': langVersion,
      'nullableEnabled': nullableEnabled,
      'packageReferences': packageReferences,
      'normalizedTrees': normalizedTrees,
    };

Map<String, dynamic> _diagnosticJson({
  String severity = 'error',
  String code = 'RF0001',
  String message = 'Something went wrong',
  String? source,
  Map<String, dynamic>? location,
}) {
  final m = <String, dynamic>{
    'severity': severity,
    'code': code,
    'message': message,
  };
  if (source != null) m['source'] = source;
  if (location != null) m['location'] = location;
  return m;
}

Map<String, dynamic> _frontendResultJson({
  List<Map<String, dynamic>> units = const [],
  List<Map<String, dynamic>> diagnostics = const [],
  bool success = true,
}) =>
    {
      'units': units,
      'diagnostics': diagnostics,
      'success': success,
    };

void main() {
  // -------------------------------------------------------------------------
  // FrontendResult top-level
  // -------------------------------------------------------------------------
  group('FrontendResult', () {
    test('deserializes empty result with success=true', () {
      final json = _frontendResultJson();
      final result = _deserializer.fromJson(json);

      expect(result.success, isTrue);
      expect(result.units, isEmpty);
      expect(result.diagnostics, isEmpty);
    });

    test('deserializes success=false', () {
      final json = _frontendResultJson(success: false);
      final result = _deserializer.fromJson(json);

      expect(result.success, isFalse);
    });

    test('deserializes multiple units', () {
      final json = _frontendResultJson(units: [
        _frontendUnitJson(projectName: 'Alpha'),
        _frontendUnitJson(projectName: 'Beta', outputKind: 'library'),
      ]);
      final result = _deserializer.fromJson(json);

      expect(result.units, hasLength(2));
      expect(result.units[0].projectName, 'Alpha');
      expect(result.units[1].projectName, 'Beta');
    });

    test('deserializes multiple diagnostics', () {
      final json = _frontendResultJson(
        success: false,
        diagnostics: [
          _diagnosticJson(severity: 'error', code: 'RF0001'),
          _diagnosticJson(severity: 'warning', code: 'RF0002'),
        ],
      );
      final result = _deserializer.fromJson(json);

      expect(result.diagnostics, hasLength(2));
      expect(result.diagnostics[0].severity, DiagnosticSeverity.error);
      expect(result.diagnostics[1].severity, DiagnosticSeverity.warning);
    });
  });

  // -------------------------------------------------------------------------
  // FrontendUnit
  // -------------------------------------------------------------------------
  group('FrontendUnit', () {
    test('deserializes all scalar fields', () {
      final json = _frontendResultJson(units: [
        _frontendUnitJson(
          projectName: 'MyLib',
          outputKind: 'library',
          targetFramework: 'net7.0',
          langVersion: '11.0',
          nullableEnabled: false,
        ),
      ]);
      final unit = _deserializer.fromJson(json).units.first;

      expect(unit.projectName, 'MyLib');
      expect(unit.outputKind, OutputKind.library);
      expect(unit.targetFramework, 'net7.0');
      expect(unit.langVersion, '11.0');
      expect(unit.nullableEnabled, isFalse);
    });

    test('deserializes outputKind exe', () {
      final unit = _deserializer
          .fromJson(_frontendResultJson(units: [_frontendUnitJson(outputKind: 'exe')]))
          .units
          .first;
      expect(unit.outputKind, OutputKind.exe);
    });

    test('deserializes outputKind winExe', () {
      final unit = _deserializer
          .fromJson(_frontendResultJson(units: [_frontendUnitJson(outputKind: 'winExe')]))
          .units
          .first;
      expect(unit.outputKind, OutputKind.winExe);
    });

    test('throws on unknown outputKind', () {
      expect(
        () => _deserializer.fromJson(
            _frontendResultJson(units: [_frontendUnitJson(outputKind: 'unknown')])),
        throwsArgumentError,
      );
    });

    test('deserializes package references', () {
      final unit = _deserializer
          .fromJson(_frontendResultJson(units: [
            _frontendUnitJson(packageReferences: [
              _packageRefJson(packageName: 'Newtonsoft.Json', version: '13.0.1', tier: 1,
                  dartMapping: _dartMappingJson()),
              _packageRefJson(packageName: 'Serilog', version: '3.0.0', tier: 2),
            ]),
          ]))
          .units
          .first;

      expect(unit.packageReferences, hasLength(2));
      expect(unit.packageReferences[0].packageName, 'Newtonsoft.Json');
      expect(unit.packageReferences[0].tier, 1);
      expect(unit.packageReferences[0].dartMapping, isNotNull);
      expect(unit.packageReferences[0].dartMapping!.dartPackageName, 'json_serializable');
      expect(unit.packageReferences[1].packageName, 'Serilog');
      expect(unit.packageReferences[1].dartMapping, isNull);
    });

    test('deserializes normalized trees', () {
      final unit = _deserializer
          .fromJson(_frontendResultJson(units: [
            _frontendUnitJson(normalizedTrees: [
              _normalizedTreeJson(filePath: '/src/A.cs'),
              _normalizedTreeJson(filePath: '/src/B.cs'),
            ]),
          ]))
          .units
          .first;

      expect(unit.normalizedTrees, hasLength(2));
      expect(unit.normalizedTrees[0].filePath, '/src/A.cs');
      expect(unit.normalizedTrees[1].filePath, '/src/B.cs');
    });
  });

  // -------------------------------------------------------------------------
  // NormalizedSyntaxTree / SyntaxNode
  // -------------------------------------------------------------------------
  group('NormalizedSyntaxTree', () {
    test('deserializes root node kind and nodeId', () {
      final tree = _deserializer
          .fromJson(_frontendResultJson(units: [
            _frontendUnitJson(normalizedTrees: [
              _normalizedTreeJson(
                root: _syntaxNodeJson(nodeId: 42, kind: 'MethodDeclaration'),
              ),
            ]),
          ]))
          .units
          .first
          .normalizedTrees
          .first;

      final root = tree.root as GenericSyntaxNode;
      expect(root.nodeId, 42);
      expect(root.kind, 'MethodDeclaration');
    });

    test('deserializes nested children recursively', () {
      final root = _deserializer
          .fromJson(_frontendResultJson(units: [
            _frontendUnitJson(normalizedTrees: [
              _normalizedTreeJson(
                root: _syntaxNodeJson(
                  nodeId: 1,
                  kind: 'CompilationUnit',
                  children: [
                    _syntaxNodeJson(nodeId: 2, kind: 'ClassDeclaration', children: [
                      _syntaxNodeJson(nodeId: 3, kind: 'MethodDeclaration'),
                    ]),
                  ],
                ),
              ),
            ]),
          ]))
          .units
          .first
          .normalizedTrees
          .first
          .root as GenericSyntaxNode;

      expect(root.children, hasLength(1));
      final classNode = root.children.first as GenericSyntaxNode;
      expect(classNode.kind, 'ClassDeclaration');
      expect(classNode.children, hasLength(1));
      expect((classNode.children.first as GenericSyntaxNode).kind, 'MethodDeclaration');
    });

    test('deserializes empty symbol table', () {
      final tree = _deserializer
          .fromJson(_frontendResultJson(units: [
            _frontendUnitJson(normalizedTrees: [_normalizedTreeJson()]),
          ]))
          .units
          .first
          .normalizedTrees
          .first;

      expect(tree.symbolTable.entries, isEmpty);
    });

    test('deserializes symbol table entries with int keys', () {
      final tree = _deserializer
          .fromJson(_frontendResultJson(units: [
            _frontendUnitJson(normalizedTrees: [
              _normalizedTreeJson(
                symbolTable: _symbolTableJson({
                  '10': _resolvedSymbolJson(fullyQualifiedName: 'System.Int32', kind: 'type'),
                  '20': _resolvedSymbolJson(fullyQualifiedName: 'Console.WriteLine', kind: 'method'),
                }),
              ),
            ]),
          ]))
          .units
          .first
          .normalizedTrees
          .first;

      expect(tree.symbolTable.entries, hasLength(2));
      expect(tree.symbolTable.lookup(10)!.fullyQualifiedName, 'System.Int32');
      expect(tree.symbolTable.lookup(20)!.kind, SymbolKind.method);
      expect(tree.symbolTable.lookup(99), isNull);
    });
  });

  // -------------------------------------------------------------------------
  // ResolvedSymbol
  // -------------------------------------------------------------------------
  group('ResolvedSymbol', () {
    test('deserializes all SymbolKind values', () {
      const kinds = [
        'type', 'method', 'field', 'property', 'event', 'local', 'parameter', 'unresolved',
      ];
      const expected = [
        SymbolKind.type, SymbolKind.method, SymbolKind.field, SymbolKind.property,
        SymbolKind.event, SymbolKind.local, SymbolKind.parameter, SymbolKind.unresolved,
      ];

      for (var i = 0; i < kinds.length; i++) {
        final sym = _deserializer
            .fromJson(_frontendResultJson(units: [
              _frontendUnitJson(normalizedTrees: [
                _normalizedTreeJson(
                  symbolTable: _symbolTableJson({'1': _resolvedSymbolJson(kind: kinds[i])}),
                ),
              ]),
            ]))
            .units
            .first
            .normalizedTrees
            .first
            .symbolTable
            .lookup(1)!;
        expect(sym.kind, expected[i], reason: 'kind=${kinds[i]}');
      }
    });

    test('throws on unknown SymbolKind', () {
      expect(
        () => _deserializer.fromJson(_frontendResultJson(units: [
          _frontendUnitJson(normalizedTrees: [
            _normalizedTreeJson(
              symbolTable: _symbolTableJson({'1': _resolvedSymbolJson(kind: 'bogus')}),
            ),
          ]),
        ])),
        throwsArgumentError,
      );
    });

    test('deserializes optional sourcePackageId', () {
      final sym = _deserializer
          .fromJson(_frontendResultJson(units: [
            _frontendUnitJson(normalizedTrees: [
              _normalizedTreeJson(
                symbolTable: _symbolTableJson({
                  '1': _resolvedSymbolJson(sourcePackageId: 'Newtonsoft.Json'),
                }),
              ),
            ]),
          ]))
          .units
          .first
          .normalizedTrees
          .first
          .symbolTable
          .lookup(1)!;

      expect(sym.sourcePackageId, 'Newtonsoft.Json');
    });

    test('sourcePackageId is null when absent', () {
      final sym = _deserializer
          .fromJson(_frontendResultJson(units: [
            _frontendUnitJson(normalizedTrees: [
              _normalizedTreeJson(
                symbolTable: _symbolTableJson({'1': _resolvedSymbolJson()}),
              ),
            ]),
          ]))
          .units
          .first
          .normalizedTrees
          .first
          .symbolTable
          .lookup(1)!;

      expect(sym.sourcePackageId, isNull);
    });

    test('deserializes sourceLocation when present', () {
      final sym = _deserializer
          .fromJson(_frontendResultJson(units: [
            _frontendUnitJson(normalizedTrees: [
              _normalizedTreeJson(
                symbolTable: _symbolTableJson({
                  '1': _resolvedSymbolJson(
                    sourceLocation: _sourceLocationJson(filePath: '/src/Bar.cs', line: 5, column: 3),
                  ),
                }),
              ),
            ]),
          ]))
          .units
          .first
          .normalizedTrees
          .first
          .symbolTable
          .lookup(1)!;

      expect(sym.sourceLocation, isNotNull);
      expect(sym.sourceLocation!.filePath, '/src/Bar.cs');
      expect(sym.sourceLocation!.line, 5);
      expect(sym.sourceLocation!.column, 3);
    });

    test('sourceLocation is null when absent', () {
      final sym = _deserializer
          .fromJson(_frontendResultJson(units: [
            _frontendUnitJson(normalizedTrees: [
              _normalizedTreeJson(
                symbolTable: _symbolTableJson({'1': _resolvedSymbolJson()}),
              ),
            ]),
          ]))
          .units
          .first
          .normalizedTrees
          .first
          .symbolTable
          .lookup(1)!;

      expect(sym.sourceLocation, isNull);
    });

    test('deserializes constantValue', () {
      final sym = _deserializer
          .fromJson(_frontendResultJson(units: [
            _frontendUnitJson(normalizedTrees: [
              _normalizedTreeJson(
                symbolTable: _symbolTableJson({
                  '1': _resolvedSymbolJson(constantValue: 42),
                }),
              ),
            ]),
          ]))
          .units
          .first
          .normalizedTrees
          .first
          .symbolTable
          .lookup(1)!;

      expect(sym.constantValue, 42);
    });
  });

  // -------------------------------------------------------------------------
  // IrType hierarchy
  // -------------------------------------------------------------------------
  group('IrType', () {
    // Helper: deserialize an IrType from a ForeachAnnotation on a node
    IrType _irTypeViaForeach(Map<String, dynamic> irTypeJson) {
      final annotationJson = {
        r'$type': 'ForeachAnnotation',
        'elementType': irTypeJson,
      };
      final result = _deserializer.fromJson(_frontendResultJson(units: [
        _frontendUnitJson(normalizedTrees: [
          _normalizedTreeJson(
            root: _syntaxNodeJson(annotations: [annotationJson]),
          ),
        ]),
      ]));
      final node = result.units.first.normalizedTrees.first.root as GenericSyntaxNode;
      return (node.annotations.first as ForeachAnnotation).elementType;
    }

    test('deserializes NamedType', () {
      final t = _irTypeViaForeach(_namedTypeJson(
        symbol: _resolvedSymbolJson(fullyQualifiedName: 'System.Int32'),
      ));
      expect(t, isA<NamedType>());
      expect((t as NamedType).symbol.fullyQualifiedName, 'System.Int32');
      expect(t.typeArguments, isEmpty);
    });

    test('deserializes NamedType with type arguments', () {
      final t = _irTypeViaForeach(_namedTypeJson(
        symbol: _resolvedSymbolJson(fullyQualifiedName: 'System.Collections.Generic.List'),
        typeArguments: [_namedTypeJson(symbol: _resolvedSymbolJson(fullyQualifiedName: 'System.String'))],
      ));
      expect(t, isA<NamedType>());
      final named = t as NamedType;
      expect(named.typeArguments, hasLength(1));
      expect((named.typeArguments.first as NamedType).symbol.fullyQualifiedName, 'System.String');
    });

    test('deserializes NullableType wrapping NamedType', () {
      final t = _irTypeViaForeach(_nullableTypeJson(_namedTypeJson()));
      expect(t, isA<NullableType>());
      expect((t as NullableType).inner, isA<NamedType>());
    });

    test('deserializes FunctionType with no parameters', () {
      final t = _irTypeViaForeach(_functionTypeJson());
      expect(t, isA<FunctionType>());
      final ft = t as FunctionType;
      expect(ft.parameterTypes, isEmpty);
      expect(ft.returnType, isA<NamedType>());
    });

    test('deserializes FunctionType with parameters', () {
      final t = _irTypeViaForeach(_functionTypeJson(
        parameterTypes: [_namedTypeJson(), _namedTypeJson()],
        returnType: _dynamicTypeJson(),
      ));
      final ft = t as FunctionType;
      expect(ft.parameterTypes, hasLength(2));
      expect(ft.returnType, isA<DynamicType>());
    });

    test('deserializes DynamicType', () {
      final t = _irTypeViaForeach(_dynamicTypeJson());
      expect(t, isA<DynamicType>());
    });

    test('deserializes UnresolvedType', () {
      final t = _irTypeViaForeach(_unresolvedTypeJson());
      expect(t, isA<UnresolvedType>());
    });

    test('throws on unknown IrType discriminator', () {
      expect(
        () => _irTypeViaForeach({r'$type': 'BogusType'}),
        throwsArgumentError,
      );
    });

    test('deserializes deeply nested NullableType(FunctionType(NamedType))', () {
      final t = _irTypeViaForeach(
        _nullableTypeJson(_functionTypeJson(returnType: _namedTypeJson())),
      );
      expect(t, isA<NullableType>());
      expect((t as NullableType).inner, isA<FunctionType>());
    });
  });

  // -------------------------------------------------------------------------
  // Annotation types
  // -------------------------------------------------------------------------
  group('Annotations', () {
    // Helper: get annotations list from a node
    List<Object> _annotationsFor(List<Map<String, dynamic>> annotations) {
      final result = _deserializer.fromJson(_frontendResultJson(units: [
        _frontendUnitJson(normalizedTrees: [
          _normalizedTreeJson(
            root: _syntaxNodeJson(annotations: annotations),
          ),
        ]),
      ]));
      return (result.units.first.normalizedTrees.first.root as GenericSyntaxNode).annotations;
    }

    test('deserializes AsyncAnnotation — async method', () {
      final ann = _annotationsFor([
        {
          r'$type': 'AsyncAnnotation',
          'isAsync': true,
          'isIterator': false,
          'isFireAndForget': false,
        },
      ]).first as AsyncAnnotation;

      expect(ann.isAsync, isTrue);
      expect(ann.isIterator, isFalse);
      expect(ann.isFireAndForget, isFalse);
      expect(ann.returnTypeSymbol, isNull);
    });

    test('deserializes AsyncAnnotation with returnTypeSymbol', () {
      final ann = _annotationsFor([
        {
          r'$type': 'AsyncAnnotation',
          'isAsync': true,
          'isIterator': false,
          'isFireAndForget': false,
          'returnTypeSymbol': _resolvedSymbolJson(fullyQualifiedName: 'System.Threading.Tasks.Task'),
        },
      ]).first as AsyncAnnotation;

      expect(ann.returnTypeSymbol, isNotNull);
      expect(ann.returnTypeSymbol!.fullyQualifiedName, 'System.Threading.Tasks.Task');
    });

    test('deserializes ConfigureAwaitAnnotation', () {
      final ann = _annotationsFor([
        {r'$type': 'ConfigureAwaitAnnotation', 'configureAwait': false},
      ]).first as ConfigureAwaitAnnotation;

      expect(ann.configureAwait, isFalse);
    });

    test('deserializes OverflowCheckAnnotation checked=true', () {
      final ann = _annotationsFor([
        {r'$type': 'OverflowCheckAnnotation', 'checked': true},
      ]).first as OverflowCheckAnnotation;

      expect(ann.checked, isTrue);
    });

    test('deserializes OverflowCheckAnnotation checked=false', () {
      final ann = _annotationsFor([
        {r'$type': 'OverflowCheckAnnotation', 'checked': false},
      ]).first as OverflowCheckAnnotation;

      expect(ann.checked, isFalse);
    });

    test('deserializes ForeachAnnotation with NamedType element', () {
      final ann = _annotationsFor([
        {
          r'$type': 'ForeachAnnotation',
          'elementType': _namedTypeJson(
            symbol: _resolvedSymbolJson(fullyQualifiedName: 'System.String'),
          ),
        },
      ]).first as ForeachAnnotation;

      expect(ann.elementType, isA<NamedType>());
      expect((ann.elementType as NamedType).symbol.fullyQualifiedName, 'System.String');
    });

    test('deserializes IndexerAnnotation', () {
      final ann = _annotationsFor([
        {r'$type': 'IndexerAnnotation', 'isIndexer': true},
      ]).first as IndexerAnnotation;

      expect(ann.isIndexer, isTrue);
    });

    test('deserializes ExtensionAnnotation', () {
      final ann = _annotationsFor([
        {
          r'$type': 'ExtensionAnnotation',
          'isExtension': true,
          'extendedType': _resolvedSymbolJson(fullyQualifiedName: 'System.String'),
        },
      ]).first as ExtensionAnnotation;

      expect(ann.isExtension, isTrue);
      expect(ann.extendedType.fullyQualifiedName, 'System.String');
    });

    test('deserializes ExplicitInterfaceAnnotation', () {
      final ann = _annotationsFor([
        {
          r'$type': 'ExplicitInterfaceAnnotation',
          'implementedInterface': _resolvedSymbolJson(
            fullyQualifiedName: 'System.IDisposable',
            kind: 'type',
          ),
        },
      ]).first as ExplicitInterfaceAnnotation;

      expect(ann.implementedInterface.fullyQualifiedName, 'System.IDisposable');
    });

    test('deserializes UnsupportedAnnotation', () {
      final ann = _annotationsFor([
        {
          r'$type': 'UnsupportedAnnotation',
          'description': 'unsafe pointer arithmetic',
          'originalSourceSpan': 'int* p = &x;',
        },
      ]).first as UnsupportedAnnotation;

      expect(ann.description, 'unsafe pointer arithmetic');
      expect(ann.originalSourceSpan, 'int* p = &x;');
    });

    test('throws on unknown annotation type', () {
      expect(
        () => _annotationsFor([
          {r'$type': 'BogusAnnotation'},
        ]),
        throwsArgumentError,
      );
    });

    group('DeclarationModifiers', () {
      test('deserializes all accessibility values', () {
        const accessibilities = [
          'public', 'internal', 'protected', 'protectedInternal', 'privateProtected', 'private',
        ];
        const expected = [
          Accessibility.public, Accessibility.internal, Accessibility.protected,
          Accessibility.protectedInternal, Accessibility.privateProtected, Accessibility.private,
        ];

        for (var i = 0; i < accessibilities.length; i++) {
          final ann = _annotationsFor([
            {
              r'$type': 'DeclarationModifiers',
              'accessibility': accessibilities[i],
            },
          ]).first as DeclarationModifiers;
          expect(ann.accessibility, expected[i], reason: accessibilities[i]);
        }
      });

      test('throws on unknown accessibility', () {
        expect(
          () => _annotationsFor([
            {r'$type': 'DeclarationModifiers', 'accessibility': 'bogus'},
          ]),
          throwsArgumentError,
        );
      });

      test('all boolean flags default to false when absent', () {
        final ann = _annotationsFor([
          {r'$type': 'DeclarationModifiers', 'accessibility': 'public'},
        ]).first as DeclarationModifiers;

        expect(ann.isStatic, isFalse);
        expect(ann.isAbstract, isFalse);
        expect(ann.isVirtual, isFalse);
        expect(ann.isOverride, isFalse);
        expect(ann.isSealed, isFalse);
        expect(ann.isReadonly, isFalse);
        expect(ann.isConst, isFalse);
        expect(ann.isExtern, isFalse);
        expect(ann.isNew, isFalse);
      });
    });
  });
